import { useEffect, useState } from "react";
import "./styles/GlobalSearch.css";

export default function SearchResultsPage() {
    const [results, setResults] = useState(null);
    const [loading, setLoading] = useState(true);

    // ─────────────────────────────────────────
    // Parse query + page from hash
    // ─────────────────────────────────────────
    const hash = window.location.hash;
    const queryString = hash.includes("?") ? hash.split("?")[1] : "";
    const params = new URLSearchParams(queryString);

    const q = params.get("q") || "";
    const pageParam = parseInt(params.get("page") || "0", 10);
    const page = isNaN(pageParam) ? 0 : pageParam;

    // ─────────────────────────────────────────
    // Fetch results
    // ─────────────────────────────────────────
    useEffect(() => {
        if (!q) {
            setResults(null);
            setLoading(false);
            return;
        }

        setLoading(true);

        fetch(`/api/search?q=${encodeURIComponent(q)}&page=${page}&size=6`)
            .then(r => r.json())
            .then(data => {
                setResults(data);
                setLoading(false);
            })
            .catch(() => {
                setResults(null);
                setLoading(false);
            });
    }, [q, page]);

    // ─────────────────────────────────────────
    // States
    // ─────────────────────────────────────────
    if (loading) {
        return <div className="search-page">Searching…</div>;
    }

    if (!results) {
        return <div className="search-page">No search query.</div>;
    }

    const hasAnyResults =
        results.events.length ||
        results.clubs.length ||
        results.threads.length ||
        results.posts.length;

    // ─────────────────────────────────────────
    // Render
    // ─────────────────────────────────────────
    return (
        <div className="search-page">
            <div className="search-page-title">
                Search results for “{q}”
            </div>

            {!hasAnyResults && (
                <div className="search-empty">
                    No results found.
                </div>
            )}

            <Section title="Events" items={results.events} />
            <Section title="Clubs" items={results.clubs} />
            <Section title="Threads" items={results.threads} />
            <Section title="Posts" items={results.posts} />

            <Pagination
                page={page}
                query={q}
                hasResults={hasAnyResults}
            />
        </div>
    );
}

/* ======================================================
   SECTION
   ====================================================== */

function Section({ title, items }) {
    if (!items || items.length === 0) return null;

    return (
        <div className="search-section">
            <h3>
                {title} <span className="search-count">({items.length})</span>
            </h3>

            {items.map(item => (
                <a key={item.id} href={item.url} className="search-card">
                    <div className="search-card-title">
                        {item.title}
                    </div>

                    {item.subtitle && (
                        <div className="search-card-subtitle">
                            {item.subtitle}
                        </div>
                    )}
                </a>
            ))}
        </div>
    );
}

/* ======================================================
   PAGINATION
   ====================================================== */

function Pagination({ page, query, hasResults }) {
    if (!hasResults) return null;

    const goTo = (p) => {
        window.location.hash =
            `#/search?q=${encodeURIComponent(query)}&page=${p}`;
    };

    return (
        <div className="search-pagination">
            {page > 0 && (
                <button onClick={() => goTo(page - 1)}>
                    ← Previous
                </button>
            )}

            <span className="search-page-indicator">
                Page {page + 1}
            </span>

            <button onClick={() => goTo(page + 1)}>
                Next →
            </button>
        </div>
    );
}
